// src/components/Footer.js
import React, { useState } from "react";
import { Link } from "react-router-dom";
import { FaInstagram, FaLinkedin, FaYoutube, FaTiktok, FaSnapchat, FaChevronUp, FaChevronDown } from "react-icons/fa";
import { motion, AnimatePresence } from "framer-motion";

const Footer = () => {
  const [expanded, setExpanded] = useState(false);

  return (
    <footer className="fixed bottom-0 left-0 w-full z-50">
      <div className="bg-gray-900 text-white shadow-lg">

        {/* Toggle Bar */}
        <div
          onClick={() => setExpanded(!expanded)}
          className="cursor-pointer flex justify-center items-center py-2 bg-gray-800 hover:bg-gray-700 transition"
        >
          <span className="mr-2 font-semibold">Godemar’s Empire — Legacy in Motion</span>
          {expanded ? <FaChevronDown /> : <FaChevronUp />}
        </div>

        {/* Expandable Footer Content */}
        <AnimatePresence>
          {expanded && (
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: "auto", opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              className="overflow-hidden"
            >
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6 flex flex-col md:flex-row justify-between items-center">

                {/* Brand Info */}
                <div className="mb-4 md:mb-0">
                  <span className="text-xl font-bold">Godemar’s Empire</span>
                  <p className="text-sm mt-1">Legacy in Motion</p>
                  <p className="text-sm mt-1">Email: info@godemars.com | Phone: +123 456 7890</p>
                </div>

                {/* Quick Links */}
                <div className="flex flex-col md:flex-row space-y-2 md:space-y-0 md:space-x-6 text-sm">
                  <Link to="/">Home</Link>
                  <Link to="/about">About</Link>
                  <Link to="/purpose">Purpose</Link>
                  <Link to="/vision">Vision</Link>
                  <Link to="/domains">Domains</Link>
                  <Link to="/team">Team</Link>
                  <Link to="/careers">Careers</Link>
                  <Link to="/contact">Contact</Link>
                </div>

                {/* Social Icons */}
                <div className="flex space-x-4 mt-4 md:mt-0 text-xl">
                  <a href="#" target="_blank" rel="noreferrer"><FaInstagram /></a>
                  <a href="#" target="_blank" rel="noreferrer"><FaLinkedin /></a>
                  <a href="#" target="_blank" rel="noreferrer"><FaYoutube /></a>
                  <a href="#" target="_blank" rel="noreferrer"><FaTiktok /></a>
                  <a href="#" target="_blank" rel="noreferrer"><FaSnapchat /></a>
                </div>

              </div>

              {/* Copyright */}
              <div className="text-center text-xs text-gray-400 pb-4">
                &copy; {new Date().getFullYear()} Godemar’s Empire. All rights reserved.
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </footer>
  );
};

export default Footer;
